using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpHttpServer;

[McpServerResourceType]
public class ConfigResourceHandler
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    private static readonly Dictionary<string, object> AppSettings = new()
    {
        ["DatabaseConnectionTimeout"] = 30,
        ["MaxRetryAttempts"] = 3,
        ["FeatureFlags"] = new Dictionary<string, bool>
        {
            ["DarkMode"] = true,
            ["BetaFeatures"] = false,
        },
        ["ApiVersion"] = "v2",
    };

    private static readonly Dictionary<string, Dictionary<string, object>> PerEnvironment = new()
    {
        ["development"] = new()
        {
            ["LogLevel"] = "Debug",
            ["EnableSwagger"] = true,
            ["DatabaseHost"] = "localhost",
        },
        ["production"] = new()
        {
            ["LogLevel"] = "Warning",
            ["EnableSwagger"] = false,
            ["DatabaseHost"] = "db.prod.internal",
        },
    };

    [McpServerResource(Uri = "config://app-settings")]
    [Description("Returns the global application configuration including feature flags")]
    public string GetAppSettings()
    {
        return JsonSerializer.Serialize(AppSettings, JsonOptions);
    }

    [McpServerResource(Uri = "config://environment/{env}")]
    [Description("Returns environment-specific configuration (development or production)")]
    public string GetEnvironmentConfig(string env)
    {
        if (!PerEnvironment.TryGetValue(env.ToLowerInvariant(), out var config))
        {
            throw new McpException($"Unknown environment '{env}'. Use 'development' or 'production'.");
        }

        return JsonSerializer.Serialize(config, JsonOptions);
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpHttpServer;

[McpServerToolType]
public class ServerTools
{
    [McpServerTool]
    [Description("Returns the current server time in UTC")]
    public string GetServerTime()
    {
        return DateTime.UtcNow.ToString("o");
    }

    [McpServerTool]
    [Description("Echoes a message back, useful for connectivity testing")]
    public string Echo([Description("The message to echo")] string message)
    {
        return $"Echo: {message}";
    }
}

